import { useCallback, useEffect, useRef, useState } from 'react';
import { createArrowNav, type ArrowNav } from '@arvo/core';
import type { ListItemBase } from '@arvo/core';

export interface UseListNavigationOptions {
  items: ListItemBase[];
  onSelect: (item: ListItemBase, index: number) => void;
  onEscape?: () => void;
  wrap?: boolean;
  enabled?: boolean;
  scrollToIndex?: (index: number) => void;
}

export interface UseListNavigationReturn {
  activeIndex: number;
  setActiveIndex: (index: number) => void;
  handleKeyDown: (event: React.KeyboardEvent) => void;
}

/**
 * Thin React wrapper around `createArrowNav` for list/menu keyboard navigation.
 * Maps `ListItemBase.disabled` to `skipDisabled` and `ListItemBase.label` to
 * `typeAhead.getLabel` automatically.
 */
export function useListNavigation(
  options: UseListNavigationOptions,
): UseListNavigationReturn {
  const {
    items,
    onSelect,
    onEscape,
    wrap = true,
    enabled = true,
    scrollToIndex,
  } = options;

  const [activeIndex, setActiveIndex] = useState(0);

  const navRef = useRef<ArrowNav | null>(null);
  const onSelectRef = useRef(onSelect);
  const onEscapeRef = useRef(onEscape);
  const scrollToIndexRef = useRef(scrollToIndex);
  const itemsRef = useRef(items);

  onSelectRef.current = onSelect;
  onEscapeRef.current = onEscape;
  scrollToIndexRef.current = scrollToIndex;
  itemsRef.current = items;

  // Stable DOM element list used as ArrowNav's `items` parameter.
  // ArrowNav requires HTMLElement[], but the actual elements are only used as
  // identity tokens passed to callbacks. We create lightweight placeholders.
  const placeholdersRef = useRef<HTMLElement[]>([]);

  useEffect(() => {
    if (!enabled) {
      navRef.current?.destroy();
      navRef.current = null;
      return;
    }

    const placeholders: HTMLElement[] = items.map(
      () => document.createElement('span'),
    );
    placeholdersRef.current = placeholders;

    const nav = createArrowNav({
      items: placeholders,
      orientation: 'vertical',
      wrap,
      onNavigate(_item: HTMLElement, index: number) {
        setActiveIndex(index);
        scrollToIndexRef.current?.(index);
      },
      onSelect(_item: HTMLElement, index: number) {
        onSelectRef.current(itemsRef.current[index], index);
      },
      onEscape() {
        onEscapeRef.current?.();
      },
      skipDisabled(index: number) {
        return itemsRef.current[index]?.isDisabled === true;
      },
      typeAhead: {
        getLabel(index: number) {
          return itemsRef.current[index]?.label ?? '';
        },
      },
    });

    navRef.current = nav;
    return () => nav.destroy();
  }, [enabled, wrap, items]);

  const handleKeyDown = useCallback((event: React.KeyboardEvent) => {
    navRef.current?.handleKeyDown(event.nativeEvent);
  }, []);

  return { activeIndex, setActiveIndex, handleKeyDown };
}
